solution_code:
#include <stdio.h>

unsigned int get_byte(unsigned int val, int n) {
    return (val >> (n * 8)) & 0xFF;
}

unsigned int get_nibble_lo(unsigned int val) {
    return val & 0x0F;
}

unsigned int get_nibble_hi(unsigned int val) {
    return (val >> 4) & 0x0F;
}

int main(void) {
    {
        printf("%d\n", (int)(get_byte(0xDEADBEEF, 0)));
        printf("%d\n", (int)(get_byte(0xDEADBEEF, 1)));
        printf("%d\n", (int)(get_byte(0xDEADBEEF, 2)));
        printf("%d\n", (int)(get_byte(0xDEADBEEF, 3)));
    }
    {
        printf("%d\n", (int)(get_nibble_lo(0xDEADBEEF)));
        printf("%d\n", (int)(get_nibble_lo(0x12345670)));
        printf("%d\n", (int)(get_nibble_lo(0xFFFFFFAB)));
        printf("%d\n", (int)(get_nibble_lo(0x00000000)));
    }
    {
        printf("%d\n", (int)(get_nibble_hi(0xDEADBEEF)));
        printf("%d\n", (int)(get_nibble_hi(0x12345670)));
        printf("%d\n", (int)(get_nibble_hi(0xFFFFFFAB)));
        printf("%d\n", (int)(get_nibble_hi(0x00000000)));
    }
    return 0;
}

